// /learn вЂ” parse URL from message text
const text = $input.first().json.message?.text || '';
const chatId = $input.first().json.message?.chat?.id;

// Match anything after /learn that looks like an URL.
const match = text.match(/^\/learn\s+(https?:\/\/\S+)/i);
if (!match) {
  return [{ json: { chat_id: chatId, valid: false, error: 'Please send a URL after /learn.\n\nExample:\n`/learn https://martinfowler.com/articles/microservices.html`' } }];
}

const url = match[1].replace(/[)\].,;]+$/, ''); // strip trailing punctuation
return [{ json: { chat_id: chatId, valid: true, url } }];

const raw = $input.first().json.data || $input.first().json.body || '';
const chatId = $('/learn: parse URL').item.json.chat_id;
const url = $('/learn: parse URL').item.json.url;

const titleMatch = raw.match(/^Title:\s*(.+?)$/m);
const title = (titleMatch ? titleMatch[1] : 'Untitled').trim().slice(0, 200);

const markerIdx = raw.indexOf('Markdown Content:');
let content = markerIdx >= 0 ? raw.slice(markerIdx + 'Markdown Content:'.length).trim() : raw;
content = content.replace(/!\[.*?\]\(.*?\)/g, '').replace(/\s+/g, ' ').trim();
if (content.length > 14000) content = content.slice(0, 14000) + '...';

if (content.length < 200) {
  return [{ json: { chat_id: chatId, url, title, content: '', extraction_failed: true } }];
}

// Build the full Anthropic Messages API request body here using JSON.stringify
// so the article content is always safely escaped, regardless of what chars it contains.
const systemPrompt = "You are the Teacher in an AI-powered learning assistant for senior backend engineers preparing for staff-tier interviews (specialties: .NET, distributed systems, database internals, system design, software architecture). Read web articles/docs/blog posts/papers/tutorials, produce a tight structured summary helping the engineer absorb material quickly and remember parts that matter at interview time.\n\nNOT writing for a casual reader. Assume basics; surface what distinguishes senior understanding: tradeoffs, failure modes, when-to-use, hidden costs, second-order effects, contrast with alternatives.\n\nOutput JSON with EXACTLY this schema:\n{\n  \"title\": \"<short title, <=90 chars>\",\n  \"key_points\": [\"<5 to 7 sentences>\"],\n  \"main_concepts\": [\"<3 to 5 labels>\"],\n  \"difficulty\": \"beginner\" | \"intermediate\" | \"advanced\",\n  \"interview_angle\": \"<one sentence>\"\n}\n\nCalibrate difficulty against a senior backend engineer bar. Output ONLY the JSON.";

const userContent = 'TITLE_HINT: ' + title + '\nURL: ' + url + '\n\nCONTENT:\n' + content;

const teacher_body = JSON.stringify({
  model: 'claude-opus-4-7',
  max_tokens: 2000,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
});

return [{ json: { chat_id: chatId, url, title, content, extraction_failed: false, teacher_body } }];

// Parse Teacher JSON response + prep for Postgres insert
const chatId = $('/learn: extract title+body').item.json.chat_id;
const url = $('/learn: extract title+body').item.json.url;
const content = $('/learn: extract title+body').item.json.content;
const titleHint = $('/learn: extract title+body').item.json.title;

const response = $input.first().json;
const rawText = response?.content?.[0]?.text || '';

let parsed;
try {
  // Tolerate fenced output just in case
  const cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (err) {
  throw new Error('Teacher returned unparseable JSON: ' + rawText.slice(0, 300));
}

// Validate + clamp
const keyPoints = Array.isArray(parsed.key_points) ? parsed.key_points.slice(0, 7) : [];
if (keyPoints.length < 5) {
  while (keyPoints.length < 5) keyPoints.push('(see source for additional detail)');
}
const concepts = Array.isArray(parsed.main_concepts) ? parsed.main_concepts.slice(0, 5) : [];
const difficulty = ['beginner', 'intermediate', 'advanced'].includes(parsed.difficulty) ? parsed.difficulty : 'intermediate';
const title = (parsed.title || titleHint || 'Untitled').slice(0, 200);
const interviewAngle = parsed.interview_angle || '';

const summaryJson = { key_points: keyPoints, main_concepts: concepts, difficulty, interview_angle: interviewAngle };

return [{ json: { chat_id: chatId, url, title, content, difficulty, summary_json: summaryJson } }];

const row = $input.first().json;
const materialId = row.id;
const chatId = row.chat_id;
const title = row.title || 'Untitled';
const summary = row.summary_json;

function esc(s) { return String(s == null ? '' : s).replace(/([_*`\[])/g, '\$1'); }

const diffEmoji = { beginner: '🟢', intermediate: '🟡', advanced: '🔴' }[summary.difficulty] || '⚪️';
const keyPointsBlock = summary.key_points.map((p, i) => `${i + 1}. ${esc(p)}`).join('\n');
const conceptsBlock = summary.main_concepts.map((c) => `\`${esc(c)}\``).join(' · ');
const interviewBlock = summary.interview_angle ? `\n💡 *Interview angle:* _${esc(summary.interview_angle)}_` : '';

const text = `📚 *${esc(title)}*\n${diffEmoji} _${esc(summary.difficulty)}_\n\n*Key points:*\n${keyPointsBlock}\n\n*Concepts:* ${conceptsBlock}${interviewBlock}\n\nTap below to test yourself with 5 interview-style questions.`;

const reply_markup = {
  inline_keyboard: [[{ text: '🎯 Take quiz now', callback_data: `pick:${materialId}` }]]
};

const body_json = JSON.stringify({ chat_id: chatId, text, parse_mode: 'Markdown', reply_markup });
return [{ json: { chat_id: chatId, text, reply_markup, body_json } }];

const chatId = $('Telegram Trigger').item.json.message.chat.id;
const rows = $input.all().map(i => i.json);

function esc(s) { return String(s == null ? '' : s).replace(/([_*`\[])/g, '\$1'); }

let text, reply_markup;
if (!rows || rows.length === 0 || !rows[0].id) {
  text = '📭 *No saved materials yet.*\n\nSend `/learn <url>` first.';
  reply_markup = undefined;
} else {
  const diffEmoji = { beginner: '🟢', intermediate: '🟡', advanced: '🔴' };
  const inline_keyboard = rows.map((r) => [{
    text: `${diffEmoji[r.difficulty] || '⚪️'} ${(r.title || 'Untitled').slice(0, 60)}`,
    callback_data: `pick:${r.id}`
  }]);
  text = `📚 *Pick a topic to quiz on:*\n\nYou have ${rows.length} saved material${rows.length === 1 ? '' : 's'}.`;
  reply_markup = { inline_keyboard };
}

const payload = { chat_id: chatId, text, parse_mode: 'Markdown' };
if (reply_markup) payload.reply_markup = reply_markup;
const body_json = JSON.stringify(payload);
return [{ json: { chat_id: chatId, body_json } }];

parameters.query:
SELECT m.id AS material_id, m.chat_id, m.title, m.content, m.summary_json, m.difficulty
FROM app.learning_materials m
WHERE m.id = $1;

